{
  "summary": "This paper presents a comprehensive empirical study comparing multiple continual learning methods across five pre-trained language models (PLMs) on three NLP classification benchmarks under task- and class-incremental settings. It finds that rehearsal-based methods, particularly experience replay variants, are most effective at mitigating catastrophic forgetting, with BERT being the most robust PLM. A novel layer-wise probing analysis reveals that forgetting occurs not only in the classifier but also in middle layers, providing new insights for future continual learning research.",
  "strengths": [
    {
      "point": "Comprehensive benchmark combining multiple PLMs, CL methods, datasets, and settings",
      "evidence": "Evaluation of six CL methods on five PLMs across three datasets and two continual learning settings (Task-IL and Class-IL)."
    },
    {
      "point": "Insightful layer-wise probing analysis",
      "evidence": "Prototype-based layer-wise analysis reveals forgetting patterns across PLM layers, highlighting fragility in classifier and middle layers."
    },
    {
      "point": "Clear identification of experience replay methods as most effective",
      "evidence": "ER and DERPP outperform regularization and dynamic architecture methods in accuracy and backward transfer."
    },
    {
      "point": "Open sourcing code and datasets",
      "evidence": "Commitment to releasing resources to facilitate further research in NLP continual learning."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited novelty due to missing comparison with recent CL methods",
      "evidence": "No evaluation of newer parameter-efficient fine-tuning or prompt-based continual learning methods."
    },
    {
      "point": "Lack of justification for selected PLMs",
      "evidence": "No explanation for choosing BERT, ALBERT, RoBERTa, GPT2, XLNET over other influential models like T5 or ELECTRA."
    },
    {
      "point": "Insufficient ablation studies on replay buffer size and sampling",
      "evidence": "No analysis on how buffer size or sampling strategies affect experience replay performance."
    },
    {
      "point": "Evaluation metrics incomplete and upper bound baseline potentially unfair",
      "evidence": "Joint training used as upper bound is unrealistic; metrics omit memory overhead, latency, and robustness to domain shifts."
    },
    {
      "point": "Reproducibility concerns due to missing hyperparameter and implementation details",
      "evidence": "No detailed hyperparameter tuning info or clear description of prototype-based layer-wise probing and DERPP method."
    },
    {
      "point": "Clarity issues in defining continual learning settings and method descriptions",
      "evidence": "Ambiguous explanation of Task-IL vs Class-IL splits and insufficient DERPP method details."
    },
    {
      "point": "Limited generalizability and scalability discussion",
      "evidence": "No experiments on larger PLMs, longer task sequences, multi-task or multi-domain learning, or multilingual datasets."
    },
    {
      "point": "Presentation of layer-wise results could be more accessible",
      "evidence": "Layer-wise forgetting analysis is difficult to interpret without extensive background or intuitive visualization."
    }
  ],
  "questions": [
    {
      "question": "How would recent parameter-efficient or prompt-based continual learning methods compare?",
      "motivation": "Including these could provide a more comprehensive and up-to-date benchmark reflecting current advances."
    },
    {
      "question": "How sensitive are experience replay methods to buffer size and sampling strategies?",
      "motivation": "Understanding this is critical for assessing robustness and scalability in practical continual learning deployments."
    },
    {
      "question": "Can the findings generalize to larger PLMs, longer task sequences, and multilingual settings?",
      "motivation": "Real-world applications often involve larger models and diverse languages, so scalability and generalizability are important."
    },
    {
      "question": "What are the detailed mechanisms behind DERPP’s superior performance?",
      "motivation": "Clarifying this would help researchers understand and build upon the method."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
